                                EntrySearchItem(result.entry, onClick = { onEntryClick(result.entry) })
                            is SearchResult.WorkResult ->
                                WorkSearchItem(result.work)
                        }
                        HorizontalDivider(color = MaterialTheme.colorScheme.outlineVariant)
                    }
                }
            }
        }
    }
}

