                    arguments = listOf(navArgument("entryId") { type = NavType.StringType })
                ) { backStackEntry ->
                    val entryId = backStackEntry.arguments?.getString("entryId") ?: return@composable
                    CourseDetailScreen(
                        entryId = entryId,
                        onBack = { navController.popBackStack() }
